class Solution:
    def maximizeSumOfWeights(self, edges, k):
        m = len(edges)
        n = m + 1
        best = 0
        for mask in range(1 << m):
            deg = [0] * n
            total = 0
            ok = True
            for i in range(m):
                if mask & (1 << i):
                    u, v, w = edges[i]
                    deg[u] += 1
                    deg[v] += 1
                    total += w
            if any(d > k for d in deg):
                continue
            if total > best:
                best = total
        return best

