var maximizeSumOfWeights = function(edges, k) {
    const n = edges.length + 1;
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        adj[v].push([u, w]);
    }
    const dpKeep = new Array(n).fill(0);
    const dpDrop = new Array(n).fill(0);
    const parent = new Array(n).fill(-1);
    const order = [];
    const visited = new Array(n).fill(false);
    const stack = [0];
    visited[0] = true;
    while (stack.length) {
        const u = stack.pop();
        order.push(u);
        for (const [v] of adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                parent[v] = u;
                stack.push(v);
            }
        }
    }
    const bestWithCapacity = (deltas, base, cap) => {
        let total = base, cnt = 0;
        for (const d of deltas) {
            if (cnt >= cap || d <= 0) break;
            total += d;
            cnt += 1;
        }
        return total;
    };
    for (let idx = order.length - 1; idx >= 0; idx--) {
        const u = order[idx];
        let base = 0;
        const deltas = [];
        for (const [v, w] of adj[u]) {
            if (v === parent[u]) continue;
            base += dpDrop[v];
            deltas.push(w + dpKeep[v] - dpDrop[v]);
        }
        deltas.sort((a, b) => b - a);
        dpDrop[u] = bestWithCapacity(deltas, base, k);
        dpKeep[u] = bestWithCapacity(deltas, base, Math.max(k - 1, 0));
    }
    return dpDrop[0];
};
